import{_ as i,o as t,c as e,a2 as l}from"./chunks/framework.DZrHScmQ.js";const m=JSON.parse('{"title":"Docs Quality Automation","description":"","frontmatter":{"status":"Draft","owner":"待指定","scope":"organization","last_reviewed":"2026-06-15T00:00:00.000Z"},"headers":[],"relativePath":"ai-native/case-studies/docs-quality-automation.md","filePath":"ai-native/case-studies/docs-quality-automation.md"}'),o={name:"ai-native/case-studies/docs-quality-automation.md"};function d(r,a,n,c,s,u){return t(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="docs-quality-automation" tabindex="-1">Docs Quality Automation <a class="header-anchor" href="#docs-quality-automation" aria-label="Permalink to &quot;Docs Quality Automation&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p><strong>Owner：待指定</strong></p><h2 id="背景与目标" tabindex="-1">背景与目标 <a class="header-anchor" href="#背景与目标" aria-label="Permalink to &quot;背景与目标&quot;">​</a></h2><p>Evolution Handbook 是公共组织级文档库。本次优化前已有清晰目录和真源边界，但缺少：</p><ul><li>文档 CI</li><li>统一本地检查命令</li><li>文档结构 自动校验</li><li>文档 metadata</li><li>ARTI known drift 复核流程</li></ul><p>目标：用低噪音自动化保护现状，不大规模重写历史文档。</p><h2 id="原有方式" tabindex="-1">原有方式 <a class="header-anchor" href="#原有方式" aria-label="Permalink to &quot;原有方式&quot;">​</a></h2><p>主要靠人工 Review：</p><ul><li>手动检查 Markdown、YAML 和索引</li><li>手动比对 文档结构 引用</li><li>用 <code>**状态：...**</code> 记录状态</li><li>ARTI shared identifiers 有 known drift，但缺少固定输出物</li></ul><h2 id="引入的实践" tabindex="-1">引入的实践 <a class="header-anchor" href="#引入的实践" aria-label="Permalink to &quot;引入的实践&quot;">​</a></h2><ol><li><p>Docs CI baseline</p><ul><li><code>npm run check</code></li><li><code>.github/workflows/docs.yml</code></li></ul></li><li><p>文档结构 validator</p><ul><li>校验字段、ID、引用、重复 remote 和安全边界</li></ul></li><li><p>Metadata dual-track</p><ul><li><code>scripts/validate-doc-metadata.mjs</code></li><li>新文档可用 frontmatter，旧文档渐进迁移</li></ul></li><li><p>ARTI Known Drift Review</p><ul><li><code>projects/arti/playbooks/known-drift-review.md</code></li><li><code>ARTI-D007</code></li></ul></li></ol><h2 id="责任分配" tabindex="-1">责任分配 <a class="header-anchor" href="#责任分配" aria-label="Permalink to &quot;责任分配&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>责任</th></tr></thead><tbody><tr><td>提交者</td><td>核对归属、事实、状态和隐私边界</td></tr><tr><td>Reviewer</td><td>审查 Owner、证据、真源和例外</td></tr><tr><td>CI</td><td>检查 Markdown、YAML、文档结构、metadata</td></tr><tr><td>Agent</td><td>辅助发现和起草，不替代事实核对</td></tr></tbody></table><h2 id="结果" tabindex="-1">结果 <a class="header-anchor" href="#结果" aria-label="Permalink to &quot;结果&quot;">​</a></h2><p>已完成：</p><ul><li><code>npm run check</code> 作为统一检查入口</li><li>文档结构 引用和重复 remote 自动校验</li><li>部分文档带 frontmatter</li><li>shared identifiers 链接 Known Drift Review</li><li>Decision index 登记 <code>ARTI-D007</code></li></ul><h2 id="限制" tabindex="-1">限制 <a class="header-anchor" href="#限制" aria-label="Permalink to &quot;限制&quot;">​</a></h2><ul><li>CI 不验证事实正确性。</li><li>metadata 未覆盖所有历史文档。</li><li>文档结构 validator 不访问远端仓库。</li><li>Known Drift Review 不能替代跨仓测试或共享包。</li><li><code>Owner：待指定</code> 后续仍需明确。</li></ul><h2 id="可复用结论" tabindex="-1">可复用结论 <a class="header-anchor" href="#可复用结论" aria-label="Permalink to &quot;可复用结论&quot;">​</a></h2><ul><li>文档仓库先加低噪音检查，再逐步收紧。</li><li>文档结构 需要脚本校验。</li><li>metadata 迁移应渐进。</li><li>known drift 先固定 Review 输出，再考虑共享包。</li></ul><h2 id="证据" tabindex="-1">证据 <a class="header-anchor" href="#证据" aria-label="Permalink to &quot;证据&quot;">​</a></h2><ul><li><code>package.json</code></li><li><code>.github/workflows/docs.yml</code></li><li><code>scripts/validate-doc-metadata.mjs</code></li><li><code>projects/arti/playbooks/known-drift-review.md</code></li><li><code>projects/arti/decisions/ARTI-D007-shared-identifier-drift-review.md</code></li></ul>',23)])])}const p=i(o,[["render",d]]);export{m as __pageData,p as default};
